+        {100, 1.0f, true, 8.0f, false, VppConfig::PatchColoringType::MAXDIST},
+    };
+
+    for(auto& params : paramSets) {
+        // Configure VPP
+        auto vppConfig = std::make_shared<VppConfig>();
