+        messageGroup->add("disparity", disparityFrame);
+        messageGroup->add("confidence", confidenceFrame);
+
+        syncQueue->send(messageGroup);
+
+        // Check outputs
+        auto leftOut = outLeftQueue->get<ImgFrame>();
+        auto rightOut = outRightQueue->get<ImgFrame>();
